import{_ as a,o as l,c as e,a2 as i}from"./chunks/framework.CL9FnezB.js";const _=JSON.parse('{"title":"GTCDK 快速开始","description":"","frontmatter":{},"headers":[],"relativePath":"gtcdk/index.md","filePath":"gtcdk/index.md","lastUpdated":1783543150000}'),d={name:"gtcdk/index.md"};function r(o,t,n,h,c,s){return l(),e("div",null,[...t[0]||(t[0]=[i('<h1 id="gtcdk-快速开始" tabindex="-1">GTCDK 快速开始 <a class="header-anchor" href="#gtcdk-快速开始" aria-label="Permalink to &quot;GTCDK 快速开始&quot;">​</a></h1><p>GTCDK 有两套功能：</p><ul><li>CDK：礼包码、福利码、批量码。</li><li>兑换：玩家提交物品或条件，换取奖励。</li></ul><p>这两套功能可以一起用，也可以分开用。</p><h2 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h2><ol><li>安装 GTCore。</li><li>安装 Vault 和经济插件。</li><li>放入 GTCDK。</li><li>启动生成配置。</li><li>创建第一个 CDK 模板或兑换模板。</li></ol><p>GTCDK 不需要接入 GTCore 授权也能作为普通业务插件使用，但仍依赖 GTCore 的底层能力。</p><h2 id="cdk-最小流程" tabindex="-1">CDK 最小流程 <a class="header-anchor" href="#cdk-最小流程" aria-label="Permalink to &quot;CDK 最小流程&quot;">​</a></h2><ol><li>创建一个模板。</li><li>设置奖励。</li><li>生成一个 CDK。</li><li>玩家输入兑换命令。</li><li>检查奖励是否到账。</li></ol><h2 id="兑换最小流程" tabindex="-1">兑换最小流程 <a class="header-anchor" href="#兑换最小流程" aria-label="Permalink to &quot;兑换最小流程&quot;">​</a></h2><ol><li>创建一个兑换 GUI。</li><li>放入需求物品。</li><li>放入奖励物品。</li><li>保存。</li><li>玩家打开 GUI 兑换。</li></ol><h2 id="适合场景" tabindex="-1">适合场景 <a class="header-anchor" href="#适合场景" aria-label="Permalink to &quot;适合场景&quot;">​</a></h2><table tabindex="0"><thead><tr><th>场景</th><th>用法</th></tr></thead><tbody><tr><td>开服礼包</td><td>批量生成 CDK</td></tr><tr><td>节日福利</td><td>创建限时福利码</td></tr><tr><td>赞助奖励</td><td>给指定玩家 CDK</td></tr><tr><td>副本兑换</td><td>NPC 打开兑换界面</td></tr><tr><td>材料商店</td><td>多种材料换装备或宝石</td></tr></tbody></table><h2 id="设计建议" tabindex="-1">设计建议 <a class="header-anchor" href="#设计建议" aria-label="Permalink to &quot;设计建议&quot;">​</a></h2><p>CDK 和兑换不要混在一起想。<br> CDK 解决“码”的问题，兑换解决“提交东西换奖励”的问题。</p>',15)])])}const p=a(d,[["render",r]]);export{_ as __pageData,p as default};
